import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.apache.commons.text.StringEscapeUtils;

public class UserInputHandler {

    public void processInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        if (userInput != null && !userInput.isEmpty()) {
            // Sanitize user input to prevent XSS
            userInput = StringEscapeUtils.escapeHtml4(userInput);

            String output = "Hello, " + userInput + "!";

            response.setContentType("text/html");
            response.getWriter().write(output);
        } else {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Input cannot be empty");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
